      ('0100cdb0-ecbb-48e1-8a26-5746ca20757f', '2df7a38f-4fa4-4bb9-a317-bfe87dcfb454', '59ca666d-7329-4d07-8366-72cfe51219e9', FALSE, 0, '2026-04-02T05:45:41.859397', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'pending', 0.41, 'Change approval policy gap detection in GitHub workflows provides weak evidence that formal policies and review cycles may need updating.', 'related'),
