  INSERT INTO "15_sandbox"."84_fct_global_control_tests" (id, global_code, connector_type_code, version_number, bundle, source_signal_id, source_policy_id, source_library_id, source_org_id, linked_dataset_code, publish_status, is_featured, download_count, signal_count, published_by, published_at, is_active, is_deleted, created_at, updated_at)
  VALUES
      ('01db3cad-fb2c-4872-acee-28f4281ae143', 'public_repository_missing_description', 'github', 1, '{"signals": [{"signal_code": "public_repo_empty_description", "name": "Public Repository Missing Description", "description": "Detects GitHub repositories that are public but have an empty description.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    visibility = (dataset.get(\"visibility\", \"\") or \"\").upper()\n    description = dataset.get(\"description\", \"\")\n    owner = dataset.get(\"owner_login\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    if not external_id:\n        if owner and name:\n            external_id = owner + \"/\" + name\n        else:\n            external_id = name or \"unknown\"\n\n    min_description_length = 1\n    trimmed_description = (description or \"\").strip()\n    desc_length = len(trimmed_description)\n\n    if visibility == \"PUBLIC\":\n        if desc_length < min_description_length:\n            details.append({\n                \"check\": \"public_repo_description\",\n                \"status\": \"fail\",\n                \"message\": f\"Repository ''{external_id}'' is publicly accessible (visibility={visibility}) but its description is empty or whitespace (raw_description=''{description}'', trimmed_length={desc_length}), which violates the requirement for public repositories to include a meaningful description\"\n            })\n            result = \"fail\"\n            summary = f\"1/1 repositories violate the public description requirement: ''{external_id}'' is public but missing a description\"\n        else:\n            details.append({\n                \"check\": \"public_repo_description\",\n                \"status\": \"pass\",\n                \"message\": f\"Repository ''{external_id}'' is public (visibility={visibility}) and has a description with trimmed length {desc_length} characters (''{trimmed_description}''), meeting the minimum requirement of {min_description_length}\"\n            })\n            result = \"pass\"\n            summary = f\"0/1 repositories violate the public description requirement\"\n    else:\n        details.append({\n            \"check\": \"public_repo_description\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{external_id}'' is not publicly accessible (visibility={visibility}); description policy applies only to public repositories, so an empty description (''{description}'') is allowed\"\n        })\n        result = \"pass\"\n        summary = f\"0/1 repositories violate the public description requirement\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "public_repo_documentation_hygiene_issue", "name": "public_repo_documentation_hygiene_issue", "description": "", "severity_code": "low", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "public_repo_empty_description", "expected_result": "fail"}, {"signal_code": "public_repo_empty_description", "expected_result": "fail"}]}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-public_repo_empty_description-771494f3", "name": "AI Tests \u2014 public_repo_empty_description", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Public repository with a valid description", "dataset_input": {"name": "payment-api", "is_fork": "False", "pushed_at": "2025-02-11T10:12:44Z", "created_at": "2023-01-02T08:21:10Z", "is_private": "False", "updated_at": "2025-02-11T10:12:44Z", "visibility": "PUBLIC", "description": "Payment processing service for checkout flows", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "fintech-labs"}, "expected_output": {"result": "pass", "summary": "0/1 repositories violate the public description requirement", "details": [{"check": "public_repo_description", "status": "pass", "message": "Public repository has a valid description: fintech-labs/payment-api"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_002", "scenario_name": "all_fail", "description": "Public repository with empty description", "dataset_input": {"name": "internal-gateway", "is_fork": "False", "pushed_at": "2024-12-01T05:41:19Z", "created_at": "2022-03-14T11:00:00Z", "is_private": "False", "updated_at": "2024-12-01T05:41:19Z", "visibility": "PUBLIC", "description": "", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "acme-platform"}, "expected_output": {"result": "fail", "summary": "1/1 repositories violate the public description requirement", "details": [{"check": "public_repo_description", "status": "fail", "message": "Public repository has empty or too-short description: acme-platform/internal-gateway"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_003", "scenario_name": "all_compliant", "description": "Private repository with empty description", "dataset_input": {"name": "ops-terraform", "is_fork": "False", "pushed_at": "2025-01-03T03:22:01Z", "created_at": "2021-09-19T12:01:00Z", "is_private": "True", "updated_at": "2025-01-03T03:22:01Z", "visibility": "PRIVATE", "description": "", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "infra-team"}, "expected_output": {"result": "pass", "summary": "0/1 repositories violate the public description requirement", "details": [{"check": "public_repo_description", "status":