      ('01db831f-00c0-44c6-80be-72e253ef7f88', 'active_forked_repositories', 'github', 1, '{"signals": [{"signal_code": "github_active_fork_repositories", "name": "Active Forked Repositories", "description": "Detects repositories that are forks and not archived, indicating an active fork that may receive upstream changes.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"unknown\")\n    owner = dataset.get(\"owner_login\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    is_fork_raw = dataset.get(\"is_fork\", \"\")\n    is_archived_raw = dataset.get(\"is_archived\", \"\")\n\n    is_fork = str(is_fork_raw).lower() == \"true\"\n    is_archived = str(is_archived_raw).lower() == \"true\"\n\n    repo_identifier = external_id\n    if not repo_identifier:\n        if owner and name:\n            repo_identifier = owner + \"/\" + name\n        else:\n            repo_identifier = name\n\n    total_checked = 1\n    failing = 0\n\n    if is_fork:\n        failing = 1\n        details.append({\n            \"check\": \"active_fork_repo\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({repo_identifier}) is a fork (is_fork={is_fork_raw}) with archived status is_archived={is_archived_raw}, indicating it is a forked repository that may receive upstream changes and should be reviewed.\"\n        })\n    else:\n        details.append({\n            \"check\": \"active_fork_repo\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({repo_identifier}) is not a fork (is_fork={is_fork_raw}) and archived status is_archived={is_archived_raw}, so it does not present active fork risk.\"\n        })\n\n    result = \"fail\" if failing == total_checked and total_checked > 0 else \"warning\" if failing > 0 else \"pass\"\n\n    summary = f\"{failing}/{total_checked} repositories are active forks (is_fork=True)\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "github_fork_state_requires_review", "name": "github_fork_state_requires_review", "description": "", "severity_code": "low", "expression_tree": {"operator": "OR", "conditions": [{"signal_code": "github_active_fork_repositories", "expected_result": "warning"}, {"signal_code": "github_active_fork_repositories", "expected_result": "fail"}]}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-github_active_fork_repositories-78149aa8", "name": "AI Tests \u2014 github_active_fork_repositories", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Single internal repository that is not a fork", "dataset_input": {"name": "payments-api", "is_fork": "False", "pushed_at": "2025-02-11T10:14:02Z", "created_at": "2021-09-12T08:11:33Z", "is_private": "True", "updated_at": "2025-02-11T10:14:02Z", "visibility": "PRIVATE", "description": "Internal payments service", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "fintech-org"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are active forks (is_fork=True and is_archived=False)", "details": [{"check": "active_fork_repo", "status": "pass", "message": "Repository payments-api (fintech-org/payments-api) is not an active fork."}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_002", "scenario_name": "all_fail", "description": "Single repository that is a fork and still active", "dataset_input": {"name": "open-source-sync", "is_fork": "True", "pushed_at": "2025-03-01T06:4