": {"name": "analytics-pipeline", "is_archived": "False", "_asset_type": "github_repo", "_external_id": "acme/analytics-pipeline"}, "expected_output": {"result": "pass", "summary": "1/2 repositories are archived", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository analytics-pipeline (acme/analytics-pipeline) archive status evaluated"}]}, "configurable_args_override": {}, "_verification": {"original_result": "warning", "corrected_result": "pass", "reason": "The repository has is_archived=''False'', meaning it is not archived. According to the detection logic, if archived_repos == 0 after evaluation, the result is ''pass''. The ''mixed'' warning only applies when evaluating multiple records where some are archived. For this single record, the correct result is pass."}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_008", "scenario_name": "empty_dataset", "description": "Record skipped because asset type is not GitHub repository", "dataset_input": {"name": "internal-ci", "is_archived": "False", "_asset_type": "gitlab_repo", "_external_id": "acme/internal-ci"}, "expected_output": {"result": "pass", "summary": "0 repositories evaluated", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository internal-ci (acme/internal-ci) archive status evaluated"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_009", "scenario_name": "single_item_collection", "description": "Single active GitHub repository", "dataset_input": {"name": "user-profile-service", "is_archived": "False", "_asset_type": "github_repo", "_external_id": "acme/user-profile-service"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are archived", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository user-profile-service (acme/user-profile-service) archive status evaluated"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_010", "scenario_name": "single_item_collection", "description": "Single archived GitHub repository", "dataset_input": {"name": "old-payment-gateway", "is_archived": "True", "_asset_type": "github_repo", "_external_id": "acme/old-payment-gateway"}, "expected_output": {"result": "fail", "summary": "1/1 repositories are archived", "details": [{"check": "repository_archive_status", "status": "fail", "message": "Repository old-payment-gateway (acme/old-payment-gateway) archive status evaluated"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_011", "scenario_name": "config_boundary_min", "description": "Archived repository but configuration disables issue counting", "dataset_input": {"name": "archived-experiment", "is_archived": "True", "_asset_type": "github_repo", "_external_id": "acme/archived-experiment"}, "expected_output": {"result": "fail", "summary": "0/1 repositories are archived", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository archived-experiment (acme/archived-experiment) archive status evaluated"}]}, "configurable_args_override": {"treat_archived_as_issue": false}, "_verification": {"original_result": "pass", "corrected_result": "fail", "reason": "According to the detection logic, a repository with is_archived = ''True'' increments archived_repos. With a single record, archived_repos == total_repos, which results in ''fail''. The spec does not include logic that disables this via configuration, so the expected ''pass'' is incorrect."}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_012", "scenario_name": "config_