"description": "Deprecated CLI tool archived", "dataset_input": {"name": "legacy-cli-tool", "is_archived": "True", "_asset_type": "github_repo", "_external_id": "acme/legacy-cli-tool"}, "expected_output": {"result": "fail", "summary": "1/1 repositories are archived", "details": [{"check": "repository_archive_status", "status": "fail", "message": "Repository legacy-cli-tool (acme/legacy-cli-tool) archive status evaluated"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_016", "scenario_name": "empty_dataset", "description": "Non GitHub asset ignored during evaluation", "dataset_input": {"name": "artifact-storage", "is_archived": "False", "_asset_type": "bitbucket_repo", "_external_id": "acme/artifact-storage"}, "expected_output": {"result": "pass", "summary": "0 repositories evaluated", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository artifact-storage (acme/artifact-storage) archive status evaluated"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_017", "scenario_name": "boundary_value_single_archived", "description": "Another single archived boundary case", "dataset_input": {"name": "retired-billing-engine", "is_archived": "True", "_asset_type": "github_repo", "_external_id": "acme/retired-billing-engine"}, "expected_output": {"result": "fail", "summary": "1/1 repositories are archived", "details": [{"check": "repository_archive_status", "status": "fail", "message": "Repository retired-billing-engine (acme/retired-billing-engine) archive status evaluated"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_018", "scenario_name": "all_compliant", "description": "Internal tooling repository still active", "dataset_input": {"name": "devops-helper-scripts", "is_archived": "False", "_asset_type": "github_repo", "_external_id": "acme/devops-helper-scripts"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are archived", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository devops-helper-scripts (acme/devops-helper-scripts) archive status evaluated"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}], "json_schema": null}, "dataset_template": null}', '7b89f85a-c665-4a8c-93c0-fef8d24f2824', '14f1cd79-7947-436f-8d23-89d56dfacef8', NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 3, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-31T10:52:21.68659+00:00', TRUE, FALSE, '2026-03-31T10:52:21.68659+00:00', '2026-04-01T06:04:57.151413+00:00'),
      ('1f23c931-50a9-4127-ae18-4b6a8b043c3c', 'stale_repository_detection', 'github', 1, '{"signals": [{"signal_code": "github_repo_stale_push_age", "name": "GitHub Repository Stale Push Age", "description": "Detects repositories whose last push is older than a configured number of days.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    pushed_at = dataset.get(\"pushed_at\", \"\")\n\n    threshold_days = 180\n    now = datetime.datetime.now(datetime.timezone.utc)\n\n    repo_identifier = external_id if external_id else name if name else \"unknown\"\n\n    if not pushed_at:\n        details.append({\n            \"check\": \"repo_push_age\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{repo_identifier}'' has no valid pushed_at timestamp (pushed_at=''{pushed_at}''), so the repository activity age cannot be calculated against the {threshold_days}-day threshold\"\n        })\n        return {\n            \"result\": \"warning\",\n            \"summary\": f\"Repository ''{repo_identifier}'' could not be evaluated because the last push timestamp is missing\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    try:\n        if isinstance(pushed_at, datetime.datetime):\n            pushed_dt = pushed_at.astimezone(datetime.timezone.utc) if pushed_at.tzinfo else pushed_at.replace(tzinfo=datetime.timezone.utc)\n        elif isinstance(pushed_at, str):\n            s = pushed_at.strip()\n            if s.endswith(\"Z\"):\n                s = s[:-1] + \"+00:00\"\n            pushed_dt = datetime.datetime.fromisoformat(s)\n            if pushed_dt.tzinfo is None:\n                pushed_dt = pushed_dt.replace(tzinfo=datetime.timezone.utc)\n            else:\n                pushed_dt = pushed_dt.astimezone(datetime.timezone.utc)\n        else:\n            raise ValueError(\"unsupported pushed_at type\")\n    except:\n        details.append({\n            \"check\": \"repo_push_age\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{repo_identifier}'' has an invalid pushed_at value (''{pushed_at}'') which cannot be parsed as ISO8601 time, preventing comparison with the {threshold_days}-day threshold\"\n        })\n        return {\n            \"result\": \"warning\",\n            \"summary\": f\"Repository ''{repo_identifier}'' could not be evaluated due to invalid last push timestamp format\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    age_days = (now - pushed_dt).total_seconds() / 86400\n    age_days_int = int(age_days)\n\n    if age_days_int > threshold_days:\n        status = \"fail\"\n        comparison = \"above\"\n    else:\n        status = \"pass\"\n        comparison = \"below or equal to\"\n\n    details.append({\n        \"check\": \"repo_push_age\",\n        \"status\": status,\n        \"message\": f\"Repository ''{repo_identifier}'' last pushed at {pushed_at}, approximately {age_days_int} days ago, which is {comparison} the allowed {threshold_days}-day inactivity threshold\"\n    })\n\n    if status == \"fail\":\n        summary = f\"Repository ''{repo_identifier}'' last push is {age_days_int} days old, exceeding the {threshold_days}-day threshold\"\n    else:\n        summary = f\"Repository ''{repo_identifier}'' last push is {age_days_int} days old, within the {threshold_days}-day threshold\"\n\n    return {\n        \"result\": status,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "github_repository_confirmed_inactive", "name": "github_repository_confirmed_inactive", "description": "", "severity_code": "medium", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "github_repo_stale_push_age", "expected_result": "fail"}, {"operator": "NOT", "conditions": [{"signal_code": "github_repo_stale_push_age", "expected_result": "pass"}]}]}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-github_repo_stale_push_age-1bbb7d56", "name": "AI Tests \u2014 github_repo_stale_push_age", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Recent repository push well within default threshold", "dataset_input": {"pushed_at": "2026-03-01T10:15:30Z", "name": "auth-service", "_external_id": "acme/auth-service"}, "expected_output": {"result": "pass", "summary": "0/1 repositories have last push older than the allowed threshold", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository auth-service last pushed 25 days ago which is below the threshold"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_002", "scenario_name": "all_compliant", "description": "Recently updated infrastructure repository", "dataset_input": {"pushed_at": "2026-02-10T08:22:11Z", "name": "infra-terraform", "_external_id": "cloudops/infra-terraform"}, "expected_output": {"result": "pass", "summary": "0/1 repositories have last push older than the allowed threshold", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository infra-terraform last pushed 44 days ago which is below the threshold"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_003", "scenario_name": "all_fail", "description": "Repository with push older than default threshold", "dataset_input": {"pushed_at": "2025-01-12T05:10:00Z", "name": "legacy-payment-gateway", "_external_id": "fintech/