enario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_006", "scenario_name": "boundary_value", "description": "Repository pushed exactly around the boundary threshold", "dataset_input": {"pushed_at": "2025-09-27T00:00:00Z", "name": "edge-threshold-repo", "_external_id": "security/edge-threshold-repo"}, "expected_output": {"result": "pass", "summary": "0/1 repositories have last push older than the allowed threshold", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository edge-threshold-repo last pushed 180 days ago which is below the threshold"}]}, "configurable_args_override": {}, "_verification": {"original_result": "warning", "corrected_result": "pass", "reason": "The logic marks a repository as fail only if age_days > max_days_since_push (180). A push exactly ~180 days ago does not exceed the threshold, so the record should pass. The evaluate() function for a single record also does not produce ''warning''."}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_007", "scenario_name": "all_compliant", "description": "Very recent commit activity", "dataset_input": {"pushed_at": "2026-03-20T16:42:00Z", "name": "ui-dashboard", "_external_id": "frontend/ui-dashboard"}, "expected_output": {"result": "pass", "summary": "0/1 repositories have last push older than the allowed threshold", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository ui-dashboard last pushed 6 days ago which is below the threshold"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_008", "scenario_name": "all_fail", "description": "Abandoned open source mirror repository", "dataset_input": {"pushed_at": "2024-06-01T11:30:00Z", "name": "openssl-fork", "_external_id": "archive/openssl-fork"}, "expected_output": {"result": "fail", "summary": "1/1 repositories have last push older than the allowed threshold", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository openssl-fork last pushed 663 days ago which is above the threshold"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_009", "scenario_name": "single_item", "description": "Single repository slightly within acceptable activity window", "dataset_input": {"pushed_at": "2025-12-20T12:00:00Z", "name": "mobile-api", "_external_id": "apps/mobile-api"}, "expected_output": {"result": "pass", "summary": "0/1 repositories have last push older than the allowed threshold", "details": [{"check": "repo_push_age", "status": "pass", "message": "Repository mobile-api last pushed 96 days ago which is below the threshold"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_010", "scenario_name": "single_item", "description": "Single stale repository beyond threshold", "dataset_input": {"pushed_at": "2025-02-01T07:00:00Z", "name": "deprecated-auth-lib", "_external_id": "libs/deprecated-auth-lib"}, "expected_output": {"result": "fail", "summary": "1/1 repositories have last push older than the allowed threshold", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository deprecated-auth-lib last pushed 418 days ago which is above the threshold"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_011", "scenario_name": "boundary_value", "description": "Repository just under threshold", "dataset_input": {"pushed_at": "2025-09-30T10:00:00Z", "name": "near-threshold-repo", "_external_id": "platform/near-threshold-repo"}, "expected_output": {"result": "pass", "summary": "0/1 repositories have last push older than