      ('64836922-c813-4b7b-ae01-1fc7173f1ea2', 'template_repo_policy_violation', 'github', 1, '{"signals": [{"signal_code": "github_repo_template_repository_detected", "name": "GitHub Template Repository Detection", "description": "Detects repositories that are marked as template repositories.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    is_template_raw = dataset.get(\"is_template\", \"\")\n    is_template = str(is_template_raw).lower() == \"true\"\n\n    # Detect empty dataset case\n    if name == \"\" and external_id == \"\" and is_template_raw == \"\":\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"0/0 repositories are marked as template repositories\",\n            \"details\": [],\n            \"metadata\": {}\n        }\n\n    total_repos = 1\n    template_repos = 1 if is_template else 0\n\n    if is_template:\n        details.append({\n            \"check\": \"template_repository_check\",\n            \"status\": \"warning\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is marked as a template repository (is_template={is_template_raw}), meaning it can be used to generate new repositories and may require stricter governance.\"\n        })\n        result = \"warning\"\n    else:\n        details.append({\n            \"check\": \"template_repository_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not marked as a template repository (is_template={is_template_raw}), so it cannot be used as a repository template.\"\n        })\n        result = \"pass\"\n\n    summary = f\"{template_repos}/{total_repos} repositories are marked as template repositories\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "github_template_repository_configuration_warning", "name": "github_template_repository_configuration_warning", "description": "", "severity_code": "low", "expression_tree": {"signal_code": "github_repo_template_repository_detected", "expected_result": "warning"}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-github_repo_template_repository_detected-9e304608", "name": "AI Tests \u2014 github_repo_template_repository_detected", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Standard private repository not marked as template", "dataset_input": {"is_template": "False", "name": "internal-api", "_external_id": "acmecorp/internal-api"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are marked as template repositories", "details": [{"check": "template_repository_check", "status": "pass", "message": "Repository internal-api (acmecorp/internal-api) is not marked as a template repository"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_002", "scenario_name": "public_fork_not_template", "description": "Public fork repository but not a template", "dataset_input": {"is_template": "False", "name": "forked-ui-lib", "_external_id": "devhub/forked-ui-lib"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are marked as template repositories", "details": [{"check": "template_repository_check", "status": "pass", "message": "Repository forked-ui-lib (devhub/forked-ui-lib) is not marked as a template repository"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_