cted_result": null, "scenario_name": null}], "json_schema": null}, "dataset_template": null}', '6cc05487-f1d0-4efa-9021-4410485d36e1', NULL, NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 1, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-26T03:15:30.388722+00:00', TRUE, FALSE, '2026-03-26T03:15:30.388722+00:00', '2026-03-27T10:07:51.053492+00:00'),
      ('7cf7d7b1-83c2-4f5d-a51c-63083bde61cf', 'github_repository_public_visibility', 'github', 1, '{"signals": [{"signal_code": "github_repo_public_visibility_check", "name": "GitHub Repository Public Visibility", "description": "Checks whether a GitHub repository is publicly visible.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    visibility = dataset.get(\"visibility\", \"\")\n    is_private_raw = dataset.get(\"is_private\", \"\")\n\n    visibility_upper = visibility.upper()\n    is_private_lower = is_private_raw.lower()\n\n    has_data = any([\n        str(name).strip() != \"\",\n        str(visibility).strip() != \"\",\n        str(is_private_raw).strip() != \"\"\n    ])\n\n    total_repos = 0\n    public_repos = 0\n\n    if has_data:\n        total_repos = 1\n        is_public = visibility_upper == \"PUBLIC\" or is_private_lower == \"false\"\n\n        if is_public:\n            public_repos = 1\n            details.append({\n                \"check\": \"repository_public_visibility\",\n                \"status\": \"fail\",\n                \"message\": f\"Repository ''{name}'' is publicly accessible (visibility={visibility or ''N/A''}, is_private={is_private_raw or ''N/A''}), which exposes the repository to the public and violates the policy requiring private repositories.\"\n            })\n        else:\n            details.append({\n                \"check\": \"repository_public_visibility\",\n                \"status\": \"pass\",\n                \"message\": f\"Repository ''{name}'' is not publicly exposed (visibility={visibility or ''N/A''}, is_private={is_private_raw or ''N/A''}), meeting the requirement that repositories remain private.\"\n            })\n\n    has_failures = any(d[\"status\"] == \"fail\" for d in details)\n    has_warnings = any(d[\"status\"] == \"warning\" for d in details)\n\n    result = \"fail\" if has_failures else \"warning\" if has_warnings else \"pass\"\n\n    summary = f\"{public_repos}/{total_repos} repositories are publicly exposed\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "public_repository_exposure", "name": "Public Repository Exposure", "description": "Detects GitHub repositories that are publicly visible, exposing source code", "severity_code": "high", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "github_repo_public_visibility_check", "expected_result": "fail"}]}, "mitigation_guidance": null}, "policy": {"policy_code": "public_repo_visibility_check", "name": "Public Repo Visibility Check", "description": "", "actions": [{"action_type": "notification", "config": {}}], "cooldown_minutes": 0}}', 'ff099e36-d7e9-4cf2-b3f1-da91f9dfa4a1', '3d295626-cfcd-47e6-84d7-6a0a2f496756', NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 4, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-25T23:00:35.667513+00:00', TRUE, FALSE, '2026-03-25T23:00:35.667513+00:00', '2026-04-01T06:10:31.574587+00:00'),
      ('7d5ecd12-1991-401b-86be-de036ada4b6b', 'fork_code_inheritance_check', 'github', 1, '{"signals": [{"signal_code": "github_forked_repository_detected", "name": "GitHub Forked Repository Detection", "description": "Detects GitHub repositories that are forks of other repositories.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\")\n    owner = dataset.get(\"owner_login\", \"\")\n    if not external_id:\n        external_id = f\"{owner}/{name}\" if owner else name\n\n    is_fork_raw = dataset.get(\"is_fork\", \"False\")\n    is_archived_raw = dataset.get(\"is_archived\", \"False\")\n    asset_type = dataset.get(\"_asset_type\", \"github_repo\")\n\n    is_fork = str(is_fork_raw).lower() == \"true\"\n    is_archived = str(is_archived_raw).lower() == \"true\"\n\n    # Ensure we only evaluate GitHub repositories\n    if asset_type and asset_type != \"github_repo\":\n        details.append({\n            \"check\": \"asset_type_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Asset ''{external_id}'' has _asset_type={asset_type}, so it is not a GitHub repository and was not evaluated by the fork detection policy\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Asset ''{external_id}'' not applicable for GitHub fork evaluation\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    # Archived non-fork repositories are ignored (treated as zero evaluated)\n    if is_archived and not is_fork:\n        details.append({\n            \"check\": \"archived_repository_ignored\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is archived (is_archived={is_archived_raw}) and not a fork (is_fork={is_fork_raw}); archived non-fork repositories are excluded from evaluation\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"0 repositories evaluated because the repository is archived and excluded\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    # Evaluate fork status\n    if is_fork:\n        details.append({\n            \"check\": \"fork_status_check\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is marked as a fork (is_fork={is_fork_raw}), meaning it inherits code from an upstream repository which may introduce unreviewed dependencies or supply chain risk\"\n        })\n        result = \"fail\"\n        summary = \"1/1 repositories are forks\"\n    else:\n        details.append({\n            \"check\": \"fork_status_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not a fork (is_fork={is_fork_raw}), indicating it is an original repository and does not inherit upstream code\"\n        })\n        result = \"pass\"\n        summary = \"0/1 repositories are forks\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "github_forked_repository_inherited_vulnerability_risk", "name": "github_forked_repository_inherited_vulnerability_risk", "description": "", "severity_code": "medium", "expression_tree": {"signal_code": "github_forked_repository_detected", "expected_result": "fail"}, "mitigation_guidance": null}, "policy": {"policy_code": "forked_repo_vulnerability_check", "name": "Forked Repo Vulnerability Check", "description": "", "actions": [{"action_type": "notification", "config": {}}], "cooldown_minutes": 0}, "test_dataset": {"dataset_code": "ai-tests-github_forked_repository_detected-288ed717", "name": "AI Tests \u2014 github_forked_repository_detect