      ('8dc0363f-c571-4aa3-9b7e-dd6108fa9734', 'missing_repo_description_check', 'github', 2, '{"signals": [{"signal_code": "github_repo_missing_description", "name": "GitHub Repositories Missing Description", "description": "Checks whether GitHub repositories have an empty description field.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    asset_type = dataset.get(\"_asset_type\", \"\")\n    name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\", \"unknown\")\n    description_raw = dataset.get(\"description\", \"\")\n\n    if asset_type != \"github_repo\":\n        details.append({\n            \"check\": \"repo_description_present\",\n            \"status\": \"pass\",\n            \"message\": f\"Asset ''{external_id}'' has _asset_type=''{asset_type}'', so the repository description policy check is not applicable (only evaluated for _asset_type=''github_repo'')\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Asset ''{external_id}'' is not a GitHub repository; description policy not applicable\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    description_normalized = (description_raw or \"\").strip()\n\n    if description_normalized == \"\":\n        details.append({\n            \"check\": \"repo_description_present\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) has an empty description field (description=''{description_raw}''), which reduces visibility for ownership, security review, and governance\"\n        })\n        result = \"fail\"\n        summary = f\"Repository ''{name}'' ({external_id}) is missing a description\"\n    else:\n        details.append({\n            \"check\": \"repo_description_present\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) includes a description (''{description_raw}''), providing context for ownership and governance\"\n        })\n        result = \"pass\"\n        summary = f\"Repository ''{name}'' ({external_id}) has a description configured\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "repo_missing_documentation", "name": "Repository Missing Documentation", "description": "", "severity_code": "low", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "", "expected_result": "fail"}, {"signal_code": "github_repo_missing_description", "expected_result": "fail"}]}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-github_repo_missing_description-07caf903", "name": "AI Tests \u2014 github_repo_missing_description", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Repository has a proper description", "dataset_input": {"_asset_type": "github_repo", "description": "Core API gateway for payment platform", "name": "payment-gateway", "_external_id": "fintech-labs/payment-gateway"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are missing descriptions", "details": [{"check": "repo_description_present", "status": "pass", "message": "Repository payment-gateway (fintech-labs/payment-gateway) contains a valid description"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_002", "scenario_name": "all_fail", "description": "Repository with empty description", "dataset_input": {"_asset_type": "github_repo", "description": "", "name": "infra-modules", "_external_id": "acme-sec/infra-modules"}, "expected_ou