_name": "", "description": "", "record_data": {"case_id": "tc_018", "scenario_name": "all_compliant", "description": "Machine learning utilities repo", "dataset_input": {"_asset_type": "github_repo", "description": "Reusable ML feature engineering utilities", "name": "ml-feature-utils", "_external_id": "ai-platform/ml-feature-utils"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are missing descriptions", "details": [{"check": "repo_description_present", "status": "pass", "message": "Repository ml-feature-utils (ai-platform/ml-feature-utils) contains a valid description"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}], "json_schema": null}, "dataset_template": null}', '97dc663c-2466-4c9a-b484-edf77d0730ff', NULL, NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 0, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-30T05:17:29.787307+00:00', TRUE, FALSE, '2026-03-30T05:17:29.787307+00:00', '2026-03-30T05:17:29.787307+00:00'),
      ('a5f0c896-2375-4727-bb5c-71aa4600372a', 'github_private_flag_and_visibility_mismatch', 'github', 1, '{"signals": [{"signal_code": "github_private_visibility_mismatch", "name": "GitHub Private Flag and Visibility Mismatch", "description": "Detects repositories where is_private is True but visibility is not PRIVATE.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"unknown\")\n    owner = dataset.get(\"owner_login\", \"unknown-owner\")\n    external_id = dataset.get(\"_external_id\", f\"{owner}/{name}\")\n    is_private_raw = dataset.get(\"is_private\", \"\")\n    visibility = (dataset.get(\"visibility\", \"\") or \"\").upper()\n\n    is_private = str(is_private_raw).lower() == \"true\"\n\n    if not is_private:\n        details.append({\n            \"check\": \"private_visibility_consistency\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not marked private (is_private={is_private_raw}), so the visibility mismatch rule is not applicable; current visibility={visibility}\"\n        })\n        result = \"pass\"\n        summary = f\"Repository ''{name}'' is not private, so no private visibility consistency check was required\"\n    else:\n        if visibility == \"PRIVATE\":\n            details.append({\n                \"check\": \"private_visibility_consistency\",\n                \"status\": \"pass\",\n                \"message\": f\"Repository ''{name}'' ({external_id}) has consistent privacy settings with is_private={is_private_raw} and visibility={visibility}\"\n            })\n            result = \"pass\"\n            summary = f\"Repository ''{name}'' has matching private visibility settings\"\n        else:\n            details.append({\n                \"check\": \"private_visibility_consistency\",\n                \"status\": \"fail\",\n                \"message\": f\"Repository ''{name}'' ({external_id}) is marked private (is_private={is_private_raw}) but visibility is set to {visibility}, which is not PRIVATE and indicates a configuration mismatch\"\n            })\n            result = \"fail\"\n            summary = f\"Repository ''{name}'' has a mismatch between is_private={is_private_raw} and visibility={visibility}\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "github_confirmed_privacy_mismatch_condition", "name": "github_confirmed_privacy_mismatch_condition", "description": "", "severity_code": "high", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "github_private_visibility_mismatch", "expected_result": "fail"}, {"operator": "NOT", "conditions": [{"signal_code": "github_private_visibility_mismatch", "expected_result": "pass"}]}]}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-github_private_visibility_mismatch-225aabe6", "name": "AI Tests \u2014 github_private_visibility_mismatch", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Private repository correctly marked PRIVATE", "dataset_input": {"name": "auth-service", "is_fork": "False", "pushed_at": "2025-02-11T10:22:31Z", "created_at": "2023-03-01T09:11:10Z", "is_private": "True", "updated_at": "2025-02-11T10:22:31Z", "visibility": "PRIVATE", "description": "Authentication microservice", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "sec-platform"}, "expected_output": {"result": "pass", "summary": "0/1 repositories have is_private=True but visibility not PRIVATE", "details": [{"check": "private_visibility_consistency", "status": "pass", "message": "Repository auth-servi