"scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_017", "scenario_name": "mixed", "description": "Repository moderately stale but near operational boundary", "dataset_input": {"pushed_at": "2025-06-01T10:10:10Z", "name": "integration-adapters", "_external_id": "enterprise/integration-adapters"}, "expected_output": {"result": "fail", "summary": "1/1 repositories have last push older than the allowed threshold", "details": [{"check": "repo_push_age", "status": "fail", "message": "Repository integration-adapters last pushed 298 days ago which is above the threshold"}]}, "configurable_args_override": {}, "_verification": {"original_result": "warning", "corrected_result": "fail", "reason": "Per spec a repository fails if age_days > 180. With pushed_at=2025-06-01 and current date 2026-03-26, the repo is ~298 days old, exceeding the threshold. The per-record evaluation only yields pass or fail, not warning."}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_018", "scenario_name": "empty_dataset", "description": "No repository records available", "dataset_input": {"pushed_at": "", "name": "", "_external_id": ""}, "expected_output": {"result": "fail", "summary": "0/0 repositories have last push older than the allowed threshold", "details": []}, "configurable_args_override": {}, "_verification": {"original_result": "pass", "corrected_result": "fail", "reason": "The scenario ''empty_dataset'' means no records should be evaluated. The provided input is a record with required fields present but empty. Since ''pushed_at'' is required and must be a valid ISO8601 timestamp for age calculation, the detection logic cannot parse it, so the record cannot pass the check. This should result in a fail, not pass."}}, "expected_result": null, "scenario_name": null}], "json_schema": null}, "dataset_template": null}', '5becae9f-94b3-47e1-9a9d-5870d37ab675', NULL, NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 1, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-26T03:15:29.937418+00:00', TRUE, FALSE, '2026-03-26T03:15:29.937418+00:00', '2026-03-27T10:08:14.785078+00:00'),
      ('c405b9c4-5723-4aa8-8ece-acb892538ce4', 'github_repositories_should_not_be_disabled', 'github', 1, '{"signals": [{"signal_code": "github_repo_disabled_check", "name": "GitHub Repositories Should Not Be Disabled", "description": "Checks whether any GitHub repositories are marked as disabled.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"unknown\")\n    owner = dataset.get(\"owner_login\", \"unknown\")\n    external_id = dataset.get(\"_external_id\", f\"{owner}/{name}\")\n    is_disabled_raw = dataset.get(\"is_disabled\", \"False\")\n    is_disabled = is_disabled_raw.lower() == \"true\"\n    is_fork = dataset.get(\"is_fork\", \"\").lower() == \"true\"\n\n    total_repos = 1\n    disabled_repos = 0\n\n    if is_disabled and not is_fork:\n        disabled_repos = 1\n        details.append({\n            \"check\": \"repository_disabled_status\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) has is_disabled={is_disabled_raw}, indicating the repository is disabled and requires administrative or security review\"\n        })\n    elif is_disabled and is_fork:\n        details.append({\n            \"check\": \"repository_disabled_status\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) has is_disabled={is_disabled_raw} but is_fork={dataset.get(''is_fork'')}, so the disabled state is treated as acceptable for forked repositories\"\n        })\n    else:\n        details.append({\n            \"check\": \"repository_disabled_status\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) has is_disabled={is_disabled_raw}, confirming the repository is active and not disabled\"\n        })\n\n    max_allowed = 0\n\n    if disabled_repos > max_allowed:\n        result = \"fail\"\n    elif disabled_repos > 0:\n        result = \"warning\"\n    else:\n        result = \"pass\"\n\n    summary = f\"{disabled_repos}/{total_repos} repositories are disabled\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "github_repository_health_not_passing", "name": "github_repository_health_not_passing", "description": "", "severity_code": "low", "expression_tree": {"operator": "NOT", "conditions": [{"signal_code": "github_repo_disabled_check", "expected_result": "pass"}]}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-github_repo_disabled_check-435ffb4c", "name": "AI Tests \u2014 github_repo_disabled_check", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Single active private repository enabled", "dataset_input": {"name": "payments-api", "is_fork": "False", "pushed_at": "2025-02-10T11:22:13Z", "created_at": "2023-01-14T08:10:55Z", "is_private": "True", "updated_at": "2025-02-10T11:22:13Z", "visibility": "PRIVATE", "description": "Internal payments processing service", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "fintech-labs"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are disabled", "details": [{"check": "repository_disabled_status", "status": "pass", "message": "Repository payments-api (fintech-labs/payments-api) has is_disabled=False"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_002", "scenario_name": "all_compliant", "description": "Public repository enabled", "dataset_input": {"name": "open-weather-sdk", "is_fork": "False", "pushed_at": "2025-05-01T09