      ('c451eaba-aafa-4794-9001-50f179f2cb00', 'public_repo_visibility_check', 'github', 1, '{"signals": [{"signal_code": "github_repo_public_visibility_check", "name": "GitHub Repository Public Visibility", "description": "Checks whether a GitHub repository is publicly visible.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\")\n    visibility = dataset.get(\"visibility\", \"\")\n    is_private_raw = dataset.get(\"is_private\", \"\")\n\n    visibility_upper = visibility.upper()\n    is_private_lower = is_private_raw.lower()\n\n    has_data = any([\n        str(name).strip() != \"\",\n        str(visibility).strip() != \"\",\n        str(is_private_raw).strip() != \"\"\n    ])\n\n    total_repos = 0\n    public_repos = 0\n\n    if has_data:\n        total_repos = 1\n        is_public = visibility_upper == \"PUBLIC\" or is_private_lower == \"false\"\n\n        if is_public:\n            public_repos = 1\n            details.append({\n                \"check\": \"repository_public_visibility\",\n                \"status\": \"fail\",\n                \"message\": f\"Repository ''{name}'' is publicly accessible (visibility={visibility or ''N/A''}, is_private={is_private_raw or ''N/A''}), which exposes the repository to the public and violates the policy requiring private repositories.\"\n            })\n        else:\n            details.append({\n                \"check\": \"repository_public_visibility\",\n                \"status\": \"pass\",\n                \"message\": f\"Repository ''{name}'' is not publicly exposed (visibility={visibility or ''N/A''}, is_private={is_private_raw or ''N/A''}), meeting the requirement that repositories remain private.\"\n            })\n\n    has_failures = any(d[\"status\"] == \"fail\" for d in details)\n    has_warnings = any(d[\"status\"] == \"warning\" for d in details)\n\n    result = \"fail\" if has_failures else \"warning\" if has_warnings else \"pass\"\n\n    summary = f\"{public_repos}/{total_repos} repositories are publicly exposed\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "public_repository_exposure", "name": "Public Repository Exposure", "description": "Detects GitHub repositories that are publicly visible, exposing source code", "severity_code": "high", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "github_repo_public_visibility_check", "expected_result": "fail"}]}, "mitigation_guidance": null}, "policy": {"policy_code": "public_repo_visibility_check", "name": "Public Repo Visibility Check", "description": "", "actions": [{"action_type": "notification", "config": {}}], "cooldown_minutes": 0}, "test_dataset": {"dataset_code": "ai-tests-github_repo_public_visibility_check-918e9488", "name": "AI Tests \u2014 github_repo_public_visibility_check", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_private_repositories", "description": "Private repository should pass", "dataset_input": {"name": "internal-auth-service", "is_fork": "False", "pushed_at": "2025-01-10T11:22:33Z", "created_at": "2023-03-01T09:10:11Z", "is_private": "True", "updated_at": "2025-01-11T08:00:00Z", "visibility": "PRIVATE", "description": "Internal authentication microservice", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "acme-sec"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are publicly exposed", "details": [{"check": "repository_public_visibility", "status": "pass", "message": "Repository internal-auth-service is not publicly exposed"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"recor