dataset_input": {"name": "devops-helper-scripts", "is_archived": "False", "_asset_type": "github_repo", "_external_id": "acme/devops-helper-scripts"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are archived", "details": [{"check": "repository_archive_status", "status": "pass", "message": "Repository devops-helper-scripts (acme/devops-helper-scripts) archive status evaluated"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}], "json_schema": null}, "dataset_template": null}', '7b89f85a-c665-4a8c-93c0-fef8d24f2824', '14f1cd79-7947-436f-8d23-89d56dfacef8', NULL, '5496cf75-08f6-491a-8eb5-2d7ad19cfeac', NULL, 'published', FALSE, 1, 1, 'af88f921-2e07-48aa-a3e5-c556a2b2c223', '2026-03-31T10:45:07.301098+00:00', TRUE, FALSE, '2026-03-31T10:45:07.301098+00:00', '2026-03-31T12:12:36.451254+00:00'),
      ('cf927964-45e3-4cef-a6d3-28c05ef6e609', 'repository_metadata_drift_pushed_at_vs_updated_at', 'github', 1, '{"signals": [{"signal_code": "repo_metadata_drift_pushed_vs_updated", "name": "Repository Metadata Drift (pushed_at vs updated_at)", "description": "Detects repositories where pushed_at is significantly newer than updated_at, suggesting repository settings or metadata may not be maintained.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"\") or \"unknown\"\n    owner = dataset.get(\"owner_login\", \"\")\n    external_id = dataset.get(\"_external_id\", \"\")\n    if not external_id:\n        if owner:\n            external_id = owner + \"/\" + name\n        else:\n            external_id = name\n\n    pushed_at_str = dataset.get(\"pushed_at\", \"\") or \"\"\n    updated_at_str = dataset.get(\"updated_at\", \"\") or \"\"\n\n    fail_threshold_days = 90\n    warning_threshold_days = 30\n\n    if not pushed_at_str or not updated_at_str:\n        details.append({\n            \"check\": \"metadata_drift_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository {external_id} cannot be evaluated because pushed_at=''{pushed_at_str}'' and updated_at=''{updated_at_str}'' are missing or empty, so no metadata drift could be calculated\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Repository ''{external_id}'': insufficient timestamp data to detect metadata drift\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    try:\n        pushed_at = datetime.datetime.fromisoformat(pushed_at_str.replace(\"Z\", \"+00:00\"))\n        updated_at = datetime.datetime.fromisoformat(updated_at_str.replace(\"Z\", \"+00:00\"))\n    except Exception:\n        details.append({\n            \"check\": \"metadata_drift_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository {external_id} has non-parseable timestamps (pushed_at=''{pushed_at_str}'', updated_at=''{updated_at_str}''), so drift could not be computed\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Repository ''{external_id}'': timestamps could not be parsed for drift evaluation\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    diff_seconds = (pushed_at - updated_at).total_seconds()\n    drift_days = diff_seconds / 86400.0\n    drift_days_int = int(drift_days)\n\n    if drift_days <= 0:\n        status = \"pass\"\n        message = f\"Repository {external_id} has pushed_at={pushed_at_str} and updated_at={updated_at_str}; updated_at is newer or equal (drift_days={drift_days_int}), indicating repository metadata is current\"\n    elif drift_days > fail_threshold_days:\n        status = \"fail\"\n        message = f\"Repository {external_id} shows metadata drift of {drift_days_int} days (pushed_at={pushed_at_str} is much newer than updated_at={updated_at_str}), exceeding the {fail_threshold_days}-day threshold and suggesting repository settings may not be maintained\"\n    elif drift_days >= warning_threshold_days:\n        status = \"warning\"\n        message = f\"Repository {external_id} shows metadata drift of {drift_days_int} days (pushed_at={pushed_at_str} newer than updated_at={updated_at_str}), exceeding the {warning_threshold_days}-day warning threshold but not the {fail_threshold_days}-day failure threshold\"\n    else:\n        status = \"pass\"\n        message = f\"Repository {external_id} shows minimal metadata drift of {drift_days_int} days between pushed_at={pushed_at_str} and updated_at={updated_at_str}, which is within the acceptable {warning_threshold_days}-day threshold\"\n\n    details.append({\n        \"check\": \"metadata_drift_check\",\n        \"status\": status,\n        \"message\": message\n    })\n\n    result = status\n    if status == \"fail\":\n        summary = f\"Repository ''{external_id}'' shows metadata drift beyond the {fail_threshold_days}-day failure threshold\"\n    elif status == \"warning\":\n        summary = f\"Repository ''{external_id}'' shows moderate metadata drift between push activity and metadata updates\"\n    else:\n        summary = f\"Repository ''{external_id}'' metadata updates are consistent with recent code pushes\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "confirmed_repository_metadata_drift_condition", "name": "confirmed_repository_metadata_drift_condition", "description": "", "severity_code": "high", "expression_tree": {"operator": "AND", "conditions": [{"signal_code": "repo_metadata_drift_pushed_vs_updated", "expected_result": "fail"}, {"operator": "NOT", "conditions": [{"signal_code": "repo_metadata_drift_pushed_vs_updated", "expected_result": "warning"}]}]}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-repo_metadata_drift_pushed_vs_updated-93d48388", "name": "AI Tests \u2014 repo_metadata_drift_pushed_vs_updated", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Single repository with minimal drift between pushed_at and updated_at", "dataset_input": {"name": "auth-service", "is_fork": "False", "pushed_at": "2025-05-10T10:00:00Z", "created_at": "2023-01-01T09:00:00Z", "is_private": "True", "updated_at": "2025-05-08T10:00:00Z", "visibility": "PRIVATE", "description": "Authentication service", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "acme-sec"}, "expected_output": {"result": "pass", "summary": "0/1 repositories show metadata drift beyond threshold", "details": [{"ch