      ('dc249377-b403-417b-9220-47488a4bf7d3', 'forked_repo_vulnerability_check', 'github', 2, '{"signals": [{"signal_code": "github_forked_repository_detected", "name": "GitHub Forked Repository Detection", "description": "Detects GitHub repositories that are forks of other repositories.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\")\n    owner = dataset.get(\"owner_login\", \"\")\n    if not external_id:\n        external_id = f\"{owner}/{name}\" if owner else name\n\n    is_fork_raw = dataset.get(\"is_fork\", \"False\")\n    is_archived_raw = dataset.get(\"is_archived\", \"False\")\n    asset_type = dataset.get(\"_asset_type\", \"github_repo\")\n\n    is_fork = str(is_fork_raw).lower() == \"true\"\n    is_archived = str(is_archived_raw).lower() == \"true\"\n\n    # Ensure we only evaluate GitHub repositories\n    if asset_type and asset_type != \"github_repo\":\n        details.append({\n            \"check\": \"asset_type_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Asset ''{external_id}'' has _asset_type={asset_type}, so it is not a GitHub repository and was not evaluated by the fork detection policy\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": f\"Asset ''{external_id}'' not applicable for GitHub fork evaluation\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    # Archived non-fork repositories are ignored (treated as zero evaluated)\n    if is_archived and not is_fork:\n        details.append({\n            \"check\": \"archived_repository_ignored\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is archived (is_archived={is_archived_raw}) and not a fork (is_fork={is_fork_raw}); archived non-fork repositories are excluded from evaluation\"\n        })\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"0 repositories evaluated because the repository is archived and excluded\",\n            \"details\": details,\n            \"metadata\": {}\n        }\n\n    # Evaluate fork status\n    if is_fork:\n        details.append({\n            \"check\": \"fork_status_check\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is marked as a fork (is_fork={is_fork_raw}), meaning it inherits code from an upstream repository which may introduce unreviewed dependencies or supply chain risk\"\n        })\n        result = \"fail\"\n        summary = \"1/1 repositories are forks\"\n    else:\n        details.append({\n            \"check\": \"fork_status_check\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{name}'' ({external_id}) is not a fork (is_fork={is_fork_raw}), indicating it is an original repository and does not inherit upstream code\"\n        })\n        result = \"pass\"\n        summary = \"0/1 repositories are forks\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "github_forked_repository_inherited_vulnerability_risk", "name": "github_forked_repository_inherited_vulnerability_risk", "description": "", "severity_code": "medium", "expression_tree": {"signal_code": "github_forked_repository_detected", "expected_result": "fail"}, "mitigation_guidance": null}, "policy": {"policy_code": "forked_repo_vulnerability_check", "name": "Forked Repo Vulnerability Check", "description": "", "actions": [{"action_type": "notification", "config": {}}], "cooldown_minutes": 0}, "test_dataset": {"dataset_code": "ai-tests-github_forked_repository_detected-288ed717", "name": "AI Tests \u2014 github_forked_repository_de