      ('e7540170-dc2a-4398-9ab9-f5cad3ce6a4a', 'repo_outside_expected_org', 'github', 1, '{"signals": [{"signal_code": "github_repo_owner_not_expected_org", "name": "GitHub Repository Owned Outside Expected Organization", "description": "Detects repositories whose owner_login does not match the expected organization account.", "python_source": "def evaluate(dataset: dict) -> dict:\n    details = []\n\n    asset_type = dataset.get(\"_asset_type\", \"\")\n    repo_name = dataset.get(\"name\", \"unknown\")\n    external_id = dataset.get(\"_external_id\", \"unknown\")\n    owner_login = dataset.get(\"owner_login\", \"unknown\")\n\n    expected_owner = dataset.get(\"expected_owner_login\", \"kreesalis\")\n\n    if asset_type != \"github_repo\":\n        return {\n            \"result\": \"pass\",\n            \"summary\": \"No repositories found in this record (asset_type is not ''github_repo'')\",\n            \"details\": [\n                {\n                    \"check\": \"asset_type_filter\",\n                    \"status\": \"pass\",\n                    \"message\": f\"Record with external_id ''{external_id}'' has _asset_type=''{asset_type}'', so it is not evaluated as a GitHub repository\"\n                }\n            ],\n            \"metadata\": {}\n        }\n\n    if owner_login == expected_owner:\n        details.append({\n            \"check\": \"owner_login_match\",\n            \"status\": \"pass\",\n            \"message\": f\"Repository ''{repo_name}'' ({external_id}) is owned by owner_login=''{owner_login}'', which matches the expected organization account ''{expected_owner}''\"\n        })\n        failed_repos = 0\n    else:\n        details.append({\n            \"check\": \"owner_login_match\",\n            \"status\": \"fail\",\n            \"message\": f\"Repository ''{repo_name}'' ({external_id}) is owned by owner_login=''{owner_login}'', which does not match the expected organization account ''{expected_owner}'', indicating the repository is owned outside the approved organization\"\n        })\n        failed_repos = 1\n\n    total_repos = 1\n\n    if failed_repos == 0:\n        result = \"pass\"\n    elif failed_repos < total_repos:\n        result = \"warning\"\n    else:\n        result = \"fail\"\n\n    summary = f\"{failed_repos}/{total_repos} repositories are not owned by the expected organization\"\n\n    return {\n        \"result\": result,\n        \"summary\": summary,\n        \"details\": details,\n        \"metadata\": {}\n    }", "connector_type_codes": ["github"], "timeout_ms": 10000, "max_memory_mb": 256, "source_prompt": null}], "threat_type": {"threat_code": "github_repo_owner_mismatch_warning", "name": "github_repo_owner_mismatch_warning", "description": "", "severity_code": "medium", "expression_tree": {"signal_code": "github_repo_owner_not_expected_org", "expected_result": "warning"}, "mitigation_guidance": null}, "policy": null, "test_dataset": {"dataset_code": "ai-tests-github_repo_owner_not_expected_org-c80bb295", "name": "AI Tests \u2014 github_repo_owner_not_expected_org", "description": "", "record_count": 18, "records": [{"record_name": "", "description": "", "record_data": {"case_id": "tc_001", "scenario_name": "all_compliant", "description": "Repository owned by expected organization", "dataset_input": {"owner_login": "kreesalis", "_asset_type": "github_repo", "_external_id": "kreesalis/api-gateway", "name": "api-gateway"}, "expected_output": {"result": "pass", "summary": "0/1 repositories are not owned by the expected organization", "details": [{"check": "owner_login_match", "status": "pass", "message": "Repository api-gateway (kreesalis/api-gateway) owner_login=kreesalis matches expected organization"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_002", "scenario_name": "all_fail", "description": "Repository owned by unexpected personal account", "dataset_inp