, "description": "Repository matches configured expected owner", "dataset_input": {"owner_login": "central-org", "_asset_type": "github_repo", "_external_id": "central-org/logging-lib", "name": "logging-lib"}, "expected_output": {"result": "fail", "summary": "0/1 repositories are not owned by the expected organization", "details": [{"check": "owner_login_match", "status": "pass", "message": "Repository logging-lib (central-org/logging-lib) owner_login=central-org matches expected organization"}]}, "configurable_args_override": {"expected_owner_login": "central-org"}, "_verification": {"original_result": "pass", "corrected_result": "fail", "reason": "The detection logic fails any repository whose owner_login does not equal the configurable expected_owner_login. The default expected_owner_login is ''kreesalis'', but the input owner_login is ''central-org'', so this record should fail."}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_013", "scenario_name": "all_fail", "description": "Personal experimental repo detected", "dataset_input": {"owner_login": "mike-dev", "_asset_type": "github_repo", "_external_id": "mike-dev/experimental-cache", "name": "experimental-cache"}, "expected_output": {"result": "fail", "summary": "1/1 repositories are not owned by the expected organization", "details": [{"check": "owner_login_match", "status": "fail", "message": "Repository experimental-cache (mike-dev/experimental-cache) owner_login=mike-dev does not match expected organization"}]}, "configurable_args_override": {}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_014", "scenario_name": "all_compliant", "description": "Infrastructure repository under correct org", "dataset_input": {"owner_login": "kreesalis", "_asset_type": "github_repo", "_external_id": "kreesalis/terraform-live", "name": "terraform-live"}, "expected_output": {"result"