threshold of 90 days, this exceeds the threshold and should be marked as fail. No configuration overriding the threshold is provided in the input."}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_013", "scenario_name": "boundary_value", "description": "Warning threshold lowered causing warning", "dataset_input": {"name": "integration-tests", "is_fork": "False", "pushed_at": "2025-03-20T00:00:00Z", "created_at": "2024-01-10T00:00:00Z", "is_private": "True", "updated_at": "2025-03-10T00:00:00Z", "visibility": "PRIVATE", "description": "Automated integration tests", "is_archived": "False", "is_disabled": "False", "is_template": "False", "owner_login": "qa"}, "expected_output": {"result": "pass", "summary": "0/1 repositories show metadata drift beyond threshold", "details": [{"check": "metadata_drift_check", "status": "warning", "message": "Repository qa/integration-tests drift_days=10 (pushed_at newer than updated_at)"}]}, "configurable_args_override": {"warning_threshold_days": 5}, "_verification": {"original_result": "warning", "corrected_result": "pass", "reason": "pushed_at (2025-03-20) minus updated_at (2025-03-10) is 10 days, which is below the default warning_threshold_days (30). Therefore the record should pass, not warning."}}, "expected_result": null, "scenario_name": null}, {"record_name": "", "description": "", "record_data": {"case_id": "tc_014", "scenario_name": "all_fail", "description": "Archived repository evaluated when skipping disabled", "dataset_input": {"name": "retired-service", "is_fork": "False", "pushed_at": "2025-07-01T00:00:00Z", "created_at": "2015-05-05T00:00:00Z", "is_private": "True", "updated_at": "2024-12-13T00:00:00Z", "visibility": "PRIVATE", "description": "Previously retired service", "is_archived": "True", "is_disabled": "False", "is_template": "False", "owner_login": "legacy"}, "expected_output": {"result": "pass", "summary": "1/1 repositories show metadata