      ('a35208dd-3d3c-408c-8f96-1a026914a136', '9bff9540-7f37-4540-a771-cf30fd269a52', 'python_source', 'def evaluate(dataset: dict) -> dict:
    details = []

    name = dataset.get("name", "")
    visibility = dataset.get("visibility", "")
    is_private_raw = dataset.get("is_private", "")

    visibility_upper = visibility.upper()
    is_private_lower = is_private_raw.lower()

    has_data = any([
        str(name).strip() != "",
        str(visibility).strip() != "",
        str(is_private_raw).strip() != ""
    ])

    total_repos = 0
    public_repos = 0

    if has_data:
        total_repos = 1
        is_public = visibility_upper == "PUBLIC" or is_private_lower == "false"

        if is_public:
            public_repos = 1
            details.append({
                "check": "repository_public_visibility",
                "status": "fail",
                "message": f"Repository ''{name}'' is publicly accessible (visibility={visibility or ''N/A''}, is_private={is_private_raw or ''N/A''}), which exposes the repository to the public and violates the policy requiring private repositories."
            })
        else:
            details.append({
                "check": "repository_public_visibility",
                "status": "pass",
                "message": f"Repository ''{name}'' is not publicly exposed (visibility={visibility or ''N/A''}, is_private={is_private_raw or ''N/A''}), meeting the requirement that repositories remain private."
            })

    has_failures = any(d["status"] == "fail" for d in details)
    has_warnings = any(d["status"] == "warning" for d in details)

    result = "fail" if has_failures else "warning" if has_warnings else "pass"

    summary = f"{public_repos}/{total_repos} repositories are publicly exposed"

    return {
        "result": result,
        "summary": summary,
        "details": details,
        "metadata": {}
    }', '2026-03-26T01:24:52.903066', '2026-03-26T01:24:52.903066', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
      ('a4bd74c0-cbf3-4d2b-abfb-2c43878b70ac', 'c210c7eb-230b-485e-8b53-a8fab54449ee', 'python_source', 'def evaluate(dataset: dict) -> dict:
    details = []

    asset_type = dataset.get("_asset_type", "")
    name = dataset.get("name", "unknown")
    external_id = dataset.get("_external_id", "unknown")
    is_archived_raw = dataset.get("is_archived", "")
    is_archived = is_archived_raw.lower() == "true"

    total_repos = 0
    archived_repos = 0

    if asset_type != "github_repo":
        details.append({
            "check": "repository_archive_status",
            "status": "pass",
            "message": f"Record with external_id ''{external_id}'' has _asset_type=''{asset_type}'', so it is not a GitHub repository and was skipped from archived repository evaluation"
        })
        return {
            "result": "pass",
            "summary": "0 repositories evaluated",
            "details": details,
            "metadata": {}
        }

    total_repos = 1

    if is_archived:
        archived_repos = 1
        details.append({
            "check": "repository_archive_status",
            "status": "fail",
            "message": f"Repository ''{name}'' ({external_id}) is marked as archived (is_archived={is_archived_raw}), indicating the codebase is no longer actively maintained and should be reviewed for potential legacy risks"
        })
    else:
        details.append({
            "check": "repository_archive_status",
            "status": "pass",
            "message": f"Repository ''{name}'' ({external_id}) is not archived (is_archived={is_archived_raw}), indicating it remains active and does not trigger the archived repository policy check"
        })

    if total_repos == 0:
        result = "pass"
        summary = "0 repositories evaluated"
    elif archived_repos == 0:
        result = "pass"
        summary = f"{archived_repos}/{total_repos} repositories are archived"
    elif archived_repos < total_repos:
        result = "warning"
        summary = f"{archived_repos}/{total_repos} repositories are archived"
    else:
        result = "fail"
        summary = f"{archived_repos}/{total_repos} repositories are archived"

    return {
        "result": result,
        "summary": summary,
        "details": details,
        "metadata": {}
    }', '2026-03-26T01:23:48.694975', '2026-03-26T01:23:48.694975', 'af88f921-2e07-48aa-a3e5-c556a2b2c223', 'af88f921-2e07-48aa-a3e5-c556a2b2c223'),
